import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class FileHandler {
    private static final String BASE_PATH = "/path/to/files/";

    public void readFile(String fileName) {
        try {
            String safeFileName = new File(BASE_PATH, fileName).getCanonicalPath();

            if (!safeFileName.startsWith(BASE_PATH)) {
                throw new SecurityException("Invalid file path specified.");
            }

            File file = new File(safeFileName);
            FileInputStream fis = new FileInputStream(file);

            // Read file contents
            fis.close();
        } catch (IOException | SecurityException e) {
            System.out.println("File not found or could not be read.");
        }
    }

    public static void main(String[] args) {
        FileHandler fileHandler = new FileHandler();
        // User input from untrusted source
        String userInput = "../../../../../etc/passwd";
        fileHandler.readFile(userInput);
    }
}

